// ── helpers ──────────────────────────────────────────────
const yesterday = () => {
  const d = new Date();
  d.setDate(d.getDate() - 1);
  return d.toISOString().split('T')[0];
};

const todayLabel = () =>
  new Date().toLocaleDateString('en-US', {
    weekday: 'short', day: 'numeric', month: 'long', year: 'numeric'
  });

const safeRows = (data) => {
  if (!data) return [];
  if (Array.isArray(data)) return data;
  if (data.data && Array.isArray(data.data)) return data.data;
  if (data.data && data.data.rows) return data.data.rows;
  return [];
};

const findKey = (obj, patterns) => {
  const keys = Object.keys(obj);
  for (const pat of patterns) {
    const k = keys.find(k => new RegExp(pat, 'i').test(k));
    if (k) return k;
  }
  return keys[0];
};

const formatTopRows = (rows, n = 5) => {
  if (!rows || rows.length === 0) return '_(unavailable)_';
  const r0 = rows[0];
  const tk = findKey(r0, ['feedback', 'text', 'reason', 'label']);
  const ck = findKey(r0, ['downvote', 'count', 'num', 'total', 'value']);
  const top = rows.slice(0, n).map(r => `• ${r[tk]}: ${r[ck]}`).join('\n');
  const rest = rows.slice(n, 10).map(r => `"${r[tk]}" ${r[ck]}`).join(', ');
  return rest ? `${top}\n…also: ${rest}` : top;
};

// ── pull data from previous nodes ────────────────────────
const getNode = (name) => {
  try { return $node[name].json; } catch { return null; }
};

const academic    = safeRows(getNode('Q24973 Academic (21d)'));
const nonAcademic = safeRows(getNode('Q24974 Non-Academic (21d)'));
const dumpRaw     = safeRows(getNode('Q23036 Downvote Dump'));

// Filter dump to yesterday
const yest = yesterday();
const dump = dumpRaw.filter(r => {
  return Object.values(r).some(v => typeof v === 'string' && v.startsWith(yest));
}).length > 0
  ? dumpRaw.filter(r => Object.values(r).some(v => typeof v === 'string' && v.startsWith(yest)))
  : dumpRaw;

// Langfuse
const scoresData  = getNode('Langfuse Scores (24h)');
const errorsData  = getNode('Langfuse Errors (24h)');
const tracesData  = getNode('Langfuse Trace Volume');

const allScores   = scoresData?.data || [];
const downvotes   = allScores.filter(s => s.value === 0);
const comments    = downvotes
  .filter(s => s.comment && s.comment.trim())
  .slice(0, 8)
  .map(s => `"${s.comment.trim()}"`);

const allErrors   = errorsData?.data || [];
const errMap      = {};
const traceIds    = new Set();
allErrors.forEach(o => {
  const raw = o.statusMessage || o.name || 'Unknown error';
  const key = raw.replace(/\b[0-9a-f]{8,}\b/g, '').replace(/\s+/g, ' ').trim().slice(0, 70) || 'Unknown error';
  errMap[key] = (errMap[key] || 0) + 1;
  if (o.traceId) traceIds.add(o.traceId);
});
const errorsTotal = errorsData?.meta?.totalItems || allErrors.length;
const errLines    = Object.entries(errMap)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 8)
  .map(([k, v]) => `• ${k}: ${v}`)
  .join('\n') || '_(none)_';

const totalTraces = tracesData?.meta?.totalItems || '?';
const dvCount     = downvotes.length;
const dvRate      = totalTraces !== '?' ? ((dvCount / totalTraces) * 100).toFixed(2) + '%' : '?';

// Dump breakdown
let dumpSummary = `_(unavailable)_`;
if (dump.length > 0) {
  const r0 = dump[0];
  const keys = Object.keys(r0);
  const catKey = keys.find(k => /cat|type|topic|product|vertical/i.test(k));
  const reasonKey = keys.find(k => /reason|feedback|label/i.test(k));
  let lines = [`${dump.length} downvoted queries logged for ${yest}.`];
  if (catKey) {
    const cats = {};
    dump.forEach(r => { const v = r[catKey] || 'unknown'; cats[v] = (cats[v]||0)+1; });
    lines.push('Category split:');
    Object.entries(cats).sort((a,b)=>b[1]-a[1]).slice(0,5).forEach(([k,v]) => lines.push(`  ${k}: ${v}`));
  }
  if (reasonKey) {
    const reasons = {};
    dump.forEach(r => { const v = r[reasonKey] || 'unknown'; reasons[v] = (reasons[v]||0)+1; });
    lines.push('Top tagged reasons:');
    Object.entries(reasons).sort((a,b)=>b[1]-a[1]).slice(0,5).forEach(([k,v]) => lines.push(`  • ${k}: ${v}`));
  }
  dumpSummary = lines.join('\n');
}

// ── compose digest ───────────────────────────────────────
const today = todayLabel();

const digest = `:bar_chart: *Ask AI Daily Digest* — ${today}
━━━━━━━━━━━━━━━━━━━━━━━━
:thumbsdown: *Downvote Reasons — Academic (rolling 21d)*
${formatTopRows(academic)}
:thumbsdown: *Downvote Reasons — Non-Academic (rolling 21d)*
${formatTopRows(nonAcademic)}
━━━━━━━━━━━━━━━━━━━━━━━━
:bar_chart: *Yesterday's Downvoted Queries Snapshot (${yest})*
${dumpSummary}
━━━━━━━━━━━━━━━━━━━━━━━━
:speech_balloon: *User Comments on Downvotes (Langfuse, last 24h)*
Total downvotes (csat=0): ${dvCount}  |  Total traces: ${totalTraces}  |  Rate: ${dvRate}
${comments.length > 0 ? comments.slice(0,6).join('\n') : '_(No free-text comments)_'}
━━━━━━━━━━━━━━━━━━━━━━━━
:rotating_light: *Langfuse Errors (last 24h)*
Error observations: ${errorsTotal} across ${traceIds.size} unique traces
${errLines}
━━━━━━━━━━━━━━━━━━━━━━━━
:link: <https://metabase-prod.penpencil.co/question/24973|Academic Reasons> | <https://metabase-prod.penpencil.co/question/24974|Non-Academic Reasons> | <https://metabase-prod.penpencil.co/question/23036|Downvote Dump> | <https://cloud.langfuse.com|Langfuse>`;

return [{ json: { digest, today, yest, dvCount, totalTraces, dvRate } }];
